        scwin.f_SellingDecDetailRetrieve = async function(row) {
            dma_selldecunsetdetail_con.setJSON(dma_selldecunsetaggr_con.getJSON());

            let detailAllChecked = false;
            try {
                detailAllChecked = chb_detailAllYn.getSelectedIndex() != "";
            } catch(e) {
                detailAllChecked = false;
            }

            if (detailAllChecked) {
                if (dma_selldecunsetdetail_con.get("aggbilgClntNo") != null
                    && dma_selldecunsetdetail_con.get("aggbilgClntNo") != "") {
                    let crnChecked = false;
                    try {
                        crnChecked = chb_crnYn && chb_crnYn.getValue() != "";
                    } catch(e) {
                        crnChecked = false;
                    }
                    if (crnChecked) {
                        dma_selldecunsetdetail_con.set("crnYn", "Y");
                    } else {
                        dma_selldecunsetdetail_con.set("crnYn", "N");
                    }
                } else {
                    dma_selldecunsetdetail_con.set("crnYn", "");
                }
                dma_selldecunsetdetail_con.set("coCd", ed_coCd.getValue());
            } else {
                if (row != undefined && row >= 0) {
                    dma_selldecunsetdetail_con.set("aggbilgClntNo", ds_selldecunsetaggr.getCellData(row, "bilgClntNo"));
                    dma_selldecunsetdetail_con.set("aggsellItemCd", ds_selldecunsetaggr.getCellData(row, "sellItemCd"));
                    dma_selldecunsetdetail_con.set("aggtaxnClsCd", ds_selldecunsetaggr.getCellData(row, "taxnClsCd"));
                    dma_selldecunsetdetail_con.set("coCd", ed_coCd.getValue());
                }
            }

            await $c.sbm.execute(sbm_selldecunsetdetail_retrieve);
        };

