        scwin.f_openPopUpGrid = function(ds, cdColid, nmColid, gubun, pWinCloseTF) {
            let pCode = "";
            let pName = "";
            let pWtitleSearch = null;
            let pDispCnt = null;
            let pHidden = null;
            let pWhere = null;
            let rtnList = [];
            let param = null;
            let qryYear = ica_qryConDtFm.getValue().trim().substring(0, 4);
            let rowPos = ds.getRowPosition();

            if (gubun == 7 || gubun == 8) {
                let cnt = ds.getCellData(rowPos, nmColid).indexOf("]");
                pCode = ds.getCellData(rowPos, cdColid);
                pName = ds.getCellData(rowPos, nmColid).substr(cnt + 1);
            } else if (gubun == 13 || gubun == 14) {
                pCode = ds.getCellData(rowPos, cdColid) + "";
                pName = ds.getCellData(rowPos, nmColid) + "";
            } else {
                pCode = ds.getCellData(rowPos, cdColid);
                pName = ds.getCellData(rowPos, nmColid);
            }
            ds.setCellData(rowPos, cdColid, "");
            ds.setCellData(rowPos, nmColid, "");

            let pSelectID = "";

            if (gubun == 1) {
                pSelectID = "retrieveClntList2";
                pWtitleSearch = "청구처,청구처코드,청구처";
                param = ",,," + ed_coCd.getValue();
                pWhere = null;
            } else if (gubun == 2) {
                pSelectID = "retrieveClntList2";
                pWtitleSearch = "청구부서,청구부서코드,청구부서";
                pWhere = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",0";
            } else if (gubun == 3) {
                pSelectID = "retrieveSelpchItemPchsInfo";
                pWtitleSearch = "매출항목,매출항목코드,매출항목";
                pDispCnt = "2";
                pHidden = "3,4,5,6,7,8,9,10";
                pWhere = ",,1";
            } else if (gubun == 4) {
                pSelectID = "retrieveBizDomCdInfo";
                pWtitleSearch = "사업영역,사업영역코드,사업영역";
            } else if (gubun == 5) {
                pSelectID = "retrieveSelpchItemPchsInfo";
                pWtitleSearch = "매입항목,매입항목코드,매입항목";
                pDispCnt = "2";
                pHidden = "3,4,5,6,7,8,9,10";
                pWhere = ",,1";
            } else if (gubun == 6) {
                pSelectID = "retrieveSelpchItemPchsInfo";
                pWtitleSearch = "할인할증,할인할증코드,할인할증";
                pDispCnt = "2";
                pHidden = "3,4,5,6,7,8,9,10";
                pWhere = ",,1";
            } else if (gubun == 7) {
                pSelectID = "retrieveCoopList";
                pWtitleSearch = "협력업체,협력업체번호,협력업체";
            } else if (gubun == 8) {
                pSelectID = "retrieveCoopList";
                pWtitleSearch = "매입거래처,매입거래처번호,매입거래처";
                pWhere = null;
            } else if (gubun == 9) {
                pSelectID = "retrieveOpDeptCdInfo";
                pWtitleSearch = "부서,부서코드,부서";
                pWhere = ",1";
            } else if (gubun == 10) {
                pSelectID = "retrieveCommInfo";
                pWtitleSearch = "품명,품명코드,품명";
                pWhere = "2,4,,,ZZZZ";
            } else if (gubun == 11) {
                pSelectID = "retrieveLogisDeptInfo";
                pWtitleSearch = "매출부서,매출부서코드,매출부서";
                pWhere = ",,,,,,1,";
            } else if (gubun == 12) {
                pSelectID = "retrieveWrkPlInfo";
                pWtitleSearch = "작업장,작업장코드,작업장";
                pWhere = null;
            } else if (gubun == 13) {
                pSelectID = "retrieveOdrWrkPathList";
                pWhere = ds.getCellData(rowPos, "odrNo");
                pWhere = null;
            } else if (gubun == 14) {
                pSelectID = "retrieveOdrWrkPathEachWrkStpList";
                if (ds.getCellData(rowPos, "cntrSizCd") != "") {
                    pWhere = ds.getCellData(rowPos, "odrNo") + "," + ds.getCellData(rowPos, "cntrWrkPathSeq");
                } else {
                    pWhere = ds.getCellData(rowPos, "odrNo") + "," + ds.getCellData(rowPos, "bulkWrkPathSeq");
                }
            }

            scwin.isPopupOpen = true;

            return new Promise(function(resolve) {
                let settled = false;
                function safeResolve(data) {
                if (settled) return;
                settled = true;

                scwin.isPopupOpen = false;

                // pendingClick 처리 (여기서 실행)
                if (pWinCloseTF === 'T' && data && data[0] && scwin.pendingClick) {

                    let p = scwin.pendingClick;
                    scwin.pendingClick = null;

                    scwin.f_openPopUpGrid(ds_selldecunsetdetail, "bilgClntNo", columnId, 1, "F");
                } else {
                    scwin.pendingClick = null;
                }

                resolve(data);
            }

                udc_comCode_Grid.setSelectId(pSelectID);
                udc_comCode_Grid.cfCommonPopUp(function(rtnList){
                    if (rtnList != null) {
                        if (rtnList[0] == "N/A") {
                            ds.setCellData(rowPos, cdColid, ds.getOriginalCellData(rowPos, cdColid));
                            ds.setCellData(rowPos, nmColid, ds.getOriginalCellData(rowPos, nmColid));
                        } else {
                            if (gubun == 7 || gubun == 8) {
                                ds.setCellData(rowPos, cdColid, rtnList[0]);
                                ds.setCellData(rowPos, nmColid, "[" + rtnList[0] + "]" + rtnList[1]);
                            } else if (gubun == 2) {
                                ds.setCellData(rowPos, cdColid, rtnList[0]);
                            } else if (gubun == 9) {
                                ds.setCellData(rowPos, cdColid, rtnList[0]);
                                ds.setCellData(rowPos, nmColid, rtnList[1]);
                            } else {
                                ds.setCellData(rowPos, cdColid, rtnList[0]);
                                ds.setCellData(rowPos, nmColid, rtnList[1]);
                            }
                        }
                    } else {
                        ds.setCellData(rowPos, cdColid, "");
                        ds.setCellData(rowPos, nmColid, "");
                    }
                    safeResolve(rtnList);
                }
                ,
                    pCode, pName, pWinCloseTF, pDispCnt,
                    null, null, pHidden, param,
                    null, null, null, null,
                    null, "F", pWtitleSearch);

                    // X닫힘 감지
					try {

						const timeout = setTimeout(function () {

							if (!settled) {
								safeResolve(null);
							}

						}, 700); 

					} catch (e) {}
            });
        };

        scwin.f_openPopUpGridBefore = async function(colGubun, ds, cdColid, nmColid, olddata, gubun, pWinCloseTF) {
            let rowPos = ds.getRowPosition();
            if (colGubun == "CD") {
                let cdVal = ds.getCellData(rowPos, cdColid);
                if (cdVal == "") {
                    ds.setCellData(rowPos, nmColid, "");
                } else {
                    let nmVal = ds.getCellData(rowPos, nmColid);
                    if (nmVal != olddata) {
                        ds.setCellData(rowPos, nmColid, "");
                        scwin.f_openPopUpGrid(ds, cdColid, nmColid, gubun, pWinCloseTF);
                    }
                }
            } else if (colGubun == "NM") {
                let nmVal = ds.getCellData(rowPos, nmColid);
                if (nmVal == "") {
                    ds.setCellData(rowPos, cdColid, "");
                } else {
                    if (nmVal != olddata) {
                        ds.setCellData(rowPos, cdColid, "");
                        scwin.f_openPopUpGrid(ds, cdColid, nmColid, gubun, pWinCloseTF);
                    }
                }
            }
        };

