                    break;
                case "onWrkPlNm":
                    scwin.f_openPopUpGridBefore("NM", ds_selldecunsetdetail, "onWrkPlCd", columnId, value, 12, "T");
                    break;
                case "taxnClsCd":
                    if (value == "01") {
                        ds_selldecunsetdetail.setCellData(rowPos, "vatAmt", Math.round(ds_selldecunsetdetail.getCellData(rowPos, "sellAmt") * 0.1));
