                let allChecked = gr_selldecunsetdetail.getHeaderValue(0, columnIndex);
                if (allChecked == "true" || allChecked == true) {
                    for (let i = 0; i < ds_selldecunsetdetail.getRowCount(); i++) {
                        if (ds_selldecunsetdetail.getCellData(i, "dcsnClsCd") == "1") {
                            ds_selldecunsetdetail.setCellData(i, "chk", "T");
                        }
                    }
                } else {
                    for (let i = 0; i < ds_selldecunsetdetail.getRowCount(); i++) {
                        ds_selldecunsetdetail.setCellData(i, "chk", "F");
                    }
                }
            }
        };

        scwin.acb_qryConKnd_onchange = function(e) {
            if (acb_qryConKnd.getValue() == "오더번호") {
                td_udcQryConDt.setStyle("display", "none");
                td_edQryConDt.setStyle("display", "block");
            } else {
                td_udcQryConDt.setStyle("display", "block");
                td_edQryConDt.setStyle("display", "none");
            }
        };

